#!/usr/bin/env bash
set -euo pipefail

main() {
PLUGIN_DIR="$HOME/.claude/plugins/mcpmarket-my-toolkit"

echo "MCPmarket install — Target: Claude (Desktop / Code)"
echo ""

mkdir -p "$PLUGIN_DIR" "$PLUGIN_DIR/shared" "$PLUGIN_DIR/skills"
echo "  ✓ plugin directory ready at $PLUGIN_DIR"

mkdir -p "$PLUGIN_DIR/.claude-plugin"
printf '%s' 'ewogICJuYW1lIjogIm1jcG1hcmtldC1teS10b29sa2l0IiwKICAib3duZXIiOiB7CiAgICAibmFtZSI6ICJNQ1BtYXJrZXQiLAogICAgInVybCI6ICJodHRwczovL21jcG1hcmtldC5jb20iCiAgfSwKICAicGx1Z2lucyI6IFsKICAgIHsKICAgICAgIm5hbWUiOiAibWNwbWFya2V0LW15LXRvb2xraXQiLAogICAgICAic291cmNlIjogIi4vIgogICAgfQogIF0KfQo=' | base64 -d > "$PLUGIN_DIR/.claude-plugin/marketplace.json"
mkdir -p "$PLUGIN_DIR/.claude-plugin"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/.claude-plugin/plugin.json"
mkdir -p "$PLUGIN_DIR"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/README.md"
mkdir -p "$PLUGIN_DIR"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/hook-shim.sh"
chmod 755 "$PLUGIN_DIR/hook-shim.sh"
mkdir -p "$PLUGIN_DIR/hooks"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/hooks/hooks.json"
mkdir -p "$PLUGIN_DIR"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/.mcp.json"
mkdir -p "$PLUGIN_DIR/skills/sync"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/skills/sync/SKILL.md"
mkdir -p "$PLUGIN_DIR/shared"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/shared/skill-invocation.sh"
chmod 755 "$PLUGIN_DIR/shared/skill-invocation.sh"
mkdir -p "$PLUGIN_DIR/shared"
printf '%s' '' | base64 -d > "$PLUGIN_DIR/shared/sync.sh"
chmod 755 "$PLUGIN_DIR/shared/sync.sh"
echo "  ✓ wrote plugin templates + bundled skills + shared sync.sh"

# Claude Code does NOT auto-discover plugins by directory presence —
# enabling one requires four coordinated files (settings.json with
# enabledPlugins + extraKnownMarketplaces, plugins/installed_plugins.json,
# plugins/known_marketplaces.json, and a cache/ copy of the plugin), all
# under undocumented schemas that have already shifted between releases.
# Rather than re-implement that in bash and ship a broken installer the
# moment the schema moves again, we delegate to the 'claude' CLI and
# hard-fail with actionable instructions when it isn't on PATH.
if ! command -v claude >/dev/null 2>&1; then
  echo "  ✗ claude CLI not found on PATH" >&2
  echo "    Install Claude Code from https://claude.com/claude-code, then re-run this installer." >&2
  echo "    Or register manually:" >&2
  echo "      claude plugin marketplace add \"$PLUGIN_DIR\"" >&2
  echo "      claude plugin install mcpmarket-my-toolkit@mcpmarket-my-toolkit" >&2
  exit 1
fi
if ! claude plugin marketplace add "$PLUGIN_DIR" </dev/null >/dev/null 2>&1; then
  echo "  ✗ 'claude plugin marketplace add \"$PLUGIN_DIR\"' failed" >&2
  exit 1
fi
# Uninstall any prior copy so 'claude plugin install' refreshes the
# cache from disk on this run. Without this, when a returning user
# re-runs the installer the on-disk source is overwritten but the
# cached copy under ~/.claude/plugins/cache/<mkt>/<plugin>/<version>/
# is reused as-is when the version is unchanged — meaning a stale
# manifest survives across schema fixes (e.g. the duplicate-hooks
# regression after dropping plugin.json's "hooks" field). '|| true'
# swallows the non-zero exit when the plugin isn't installed yet.
claude plugin uninstall mcpmarket-my-toolkit@mcpmarket-my-toolkit </dev/null >/dev/null 2>&1 || true
if ! claude plugin install mcpmarket-my-toolkit@mcpmarket-my-toolkit </dev/null >/dev/null 2>&1; then
  echo "  ✗ 'claude plugin install mcpmarket-my-toolkit@mcpmarket-my-toolkit' failed" >&2
  exit 1
fi
echo "  ✓ registered + enabled via claude CLI"

echo ""
echo "Next:"
echo "  • Restart Claude Desktop or Claude Code to pick up the"
echo "    SessionStart hook."
echo "  • The plugin will sync your baseline skills on the next"
echo "    session start."
}

main "$@"
